{"command": "CONTAINER=$(docker ps -f name=fun4me --format "{{.Names}}" | head -1)
echo "=== CONTENT ES.JSON (product data) ==="
docker exec $CONTAINER cat /app/content/es.json | python3 -c "
import sys,json
d = json.load(sys.stdin)
print('Top keys:', list(d.keys()))
for k,v in d.items():
    if isinstance(v, list):
        print(f'  {k}: {len(v)} items')
    elif isinstance(v, dict):
        print(f'  {k}: {len(v)} subkeys')
    else:
        print(f'  {k}: {str(v)[:80]}')
" 2>/dev/null || echo "No es.json or parse error"
echo "=== CONTENT TOKENS ==="
docker exec $CONTAINER cat /app/content/tokens.json 2>/dev/null | python3 -c "
import sys,json
d = json.load(sys.stdin)
for k,v in d.items():
    if isinstance(v, dict):
        print(f'{k}: {list(v.keys())[:5]}...')
    elif isinstance(v, list):
        print(f'{k}: {len(v)} items')
    else:
        print(f'{k}: {v}')
" 2>/dev/null || echo "No tokens"", "timeout": 15}

